return msg;

// Store last Control Context v4.4.1 (Bugfix)
// Tikslas: teisingai paimti kontekstą iš Link In žinutės.
// Problema: Control flow siunčia msg.ai_context, bet senas kodas žiūrėjo tik į msg.payload.

let ctx = null;

// 1) Pirmas prioritetas: msg.ai_context (taip siunčia Control tab)
if (msg && typeof msg === 'object' && msg.ai_context && typeof msg.ai_context === 'object') {
    ctx = msg.ai_context;
}

// 2) Fallback: msg.payload.ai_context (jei kažkur supakuota į payload)
if (!ctx && msg && typeof msg === 'object' && msg.payload && typeof msg.payload === 'object' && msg.payload.ai_context) {
    ctx = msg.payload.ai_context;
}

// 3) Fallback: jei payload pats yra kontekstas
if (!ctx && msg && typeof msg === 'object' && msg.payload && typeof msg.payload === 'object') {
    // Heuristika: jei panašu į kontekstą (turi bent vieną tipinį lauką)
    const p = msg.payload;
    if (p.co2 !== undefined || p.rate_current !== undefined || p.fans !== undefined || p.rules !== undefined) {
        ctx = p;
    }
}

// 4) Fallback: jei payload yra JSON string
if (!ctx && msg && typeof msg === 'object' && typeof msg.payload === 'string') {
    try {
        const parsed = JSON.parse(msg.payload);
        if (parsed && typeof parsed === 'object') {
            if (parsed.ai_context && typeof parsed.ai_context === 'object') ctx = parsed.ai_context;
            else if (parsed.co2 !== undefined || parsed.rate_current !== undefined || parsed.fans !== undefined || parsed.rules !== undefined) ctx = parsed;
        }
    } catch (e) {
        // ignore
    }
}

// Jei vis tiek nėra – tiesiog nieko nedarom (kad nesugriautume srauto)
if (!ctx || typeof ctx !== 'object') {
    return null;
}

// Minimalus normalizavimas, kad Prompt Builder turėtų stabilias šaknis
ctx.fans = (ctx.fans && typeof ctx.fans === 'object') ? ctx.fans : {};
ctx.rules = (ctx.rules && typeof ctx.rules === 'object') ? ctx.rules : {};

// Įrašom į flow kaip source-of-truth AI Gateway pusėje
flow.set('control_context_last', ctx);
flow.set('control_context_last_ts', Date.now());

// Šis mazgas neturi tęsti srauto (tik “cache”)
return null;

