        if (!line.includes('{')) return;
        const d = JSON.parse(line.substring(line.indexOf('{')));
        const ts = new Date(d.ts).getTime();
        if (!Number.isFinite(ts)) return;

        if (ts > oneHourAgo) {
            if (d.module === 'telemetry') {
                if (Number.isFinite(Number(d.co2))) co2Values.push(Number(d.co2));
                if (Number.isFinite(Number(d.rate))) rates.push(Number(d.rate));
                if (d.alarm_state) alarmStates.add(String(d.alarm_state));
